import React, { useMemo } from "react";
import type { IRadioCheckboxListItem } from "@lmb-it/kitsconcerto-types";
import { Flex, Text } from "../../../../";
import { Pressable as RNPressable } from "react-native";
import { CoreRadioIndicator } from "@lmb-it/kitsconcertomobile";
import { useKitsTheme } from "../../../../../Contexts/Theme";

interface IRadioButtonProps<T> {
    item: IRadioCheckboxListItem<T>;
    selected: boolean;
    disabled?: boolean;
    isInvalid?: boolean;
    onToggle: () => void;
}

const indicatorSize = (s?: string): 'sm' | 'md' | 'lg' => {
    switch (s) {
        case 'xs': case 'sm': return 'sm';
        case 'lg': case 'xl': return 'lg';
        default: return 'md';
    }
};

const RadioButton = <T,>({
    item,
    selected,
    disabled,
    isInvalid,
    onToggle,
}: IRadioButtonProps<T>) => {
    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('primary');
    const borderColor = resolveToken('gray.300');

    const sizes: Record<string, number> = {
        xs: 10, sm: 15, md: 18, lg: 20, xl: 20,
    };

    const paddings: Record<string, [number, number]> = {
        xs: [2, 5], sm: [2, 5], md: [3, 9], lg: [4, 9], xl: [13, 13],
    };

    const size = item.size ? sizes[item.size] : sizes.md;
    const padding = item.size ? paddings[item.size] : paddings.md;

    /* ---- Label positioning (mirrors web) ---- */
    const leftLabel = item.labelPosition === "left";
    const bottomLabel = item.labelPosition === "bottom";
    const topLabel = item.labelPosition === "top";

    const direction =
        leftLabel ? "row-reverse" :
            bottomLabel ? "column" :
                topLabel ? "column-reverse" :
                    "row";

    /* ---- Button mode style (mirrors web checked-option) ---- */
    const containerStyle = useMemo(() => ({
        opacity: disabled ? 40 : 100,
        borderWidth: item.component ? 0 : 1,
        borderRadius: item.component ? 0 : 8,
        borderColor: selected ? primaryColor : borderColor,
        backgroundColor: selected ? primaryColor : 'transparent',
        paddingHorizontal: item.component ? 0 : padding?.[1],
        paddingVertical: item.component ? 0 : padding?.[0],
    }), [disabled, selected, item.component, padding]);

    /* ---- Content: custom component or label text ---- */
    const renderContent = () => {
        if (item.component) {
            return typeof item.component === "function"
                ? item.component({ selected, value: item.value, isInvalid: !!isInvalid })
                : item.component;
        }
        return <Text fontSize={size} fontColor={selected && !item.withBulbs ? '#fff' : undefined} m={0}>{item.label}</Text>;
    };

    /* ---- Bulb: custom radio indicator + content (mirrors web PrimeRadioButton + renderContent) ---- */
    const renderBulb = () => (
        <RNPressable
            onPress={() => { if (!disabled) onToggle(); }}
            disabled={disabled}
        >
            <Flex alignItems="center" gap={6} flexDirection={direction}>
                <CoreRadioIndicator
                    checked={selected}
                    disabled={disabled}
                    invalid={isInvalid}
                    checkedBorderColor={primaryColor}
                    dotColor={primaryColor}
                    size={indicatorSize(item.size)}
                />
                {renderContent()}
            </Flex>
        </RNPressable>
    );

    /* ---- Button: pressable container with selection colors ---- */
    const renderButton = () => (
        <RNPressable
            onPress={() => { if (!disabled) onToggle(); }}
            disabled={disabled}
        >
            <Flex style={containerStyle}>
                {renderContent()}
            </Flex>
        </RNPressable>
    );

    /* ---- Component: custom component + label (mirrors web renderComponent) ---- */
    const renderComponent = () => (
        <RNPressable
            onPress={() => { if (!disabled) onToggle(); }}
            disabled={disabled}
        >
            <Flex flexDirection={direction} alignItems="center" gap={4}>
                {renderContent()}
                {!!item.label && <Text>{item.label}</Text>}
            </Flex>
        </RNPressable>
    );

    return (
        <Flex
            pointerEvents={disabled ? "none" : "auto"}
            w={item.w}
            alignItems="flex-start"
        >
            {item.withBulbs
                ? renderBulb()
                : item.component
                    ? renderComponent()
                    : renderButton()}
        </Flex>
    );
};

export default RadioButton;
